class FreqStack:

    def __init__(self):
        self.freq = {}
        self.max_freq = 0
        self.stack = {}

    def push(self, val: int) -> None:
        if val not in self.freq:
            self.freq[val] = 1
        else:
            self.freq[val] += 1
        if self.freq[val] > self.max_freq:
            self.max_freq = self.freq[val]
        if self.freq[val] not in self.stack:
            self.stack[self.freq[val]] = []
        self.stack[self.freq[val]].append(val)

    def pop(self) -> int:
        x = self.stack[self.max_freq].pop()
        self.freq[x] -= 1
        if not self.stack[self.max_freq]:
            self.max_freq -= 1
        return x
